import json,re
d=json.load(open('/tmp/fullscan.json'))
for f in d['findings']:
    if f.get('kind')!='vulnerability': continue
    p=f['package']
    if 'bcprov-jdk15on' in p['name'] or 'bcpkix-jdk15on' in p['name']:
        fi=''
        for r in f.get('reasons',[]):
            m=re.search(r'upgrade to ([0-9][^ ,;]*)',r)
            if m: fi=m.group(1)
        print(f\"{p['name']:28} {f['id']:24} {f['severity']:7} fixed_in={fi or '-'}\")
"
